// REPLACE THIS URL WITH YOUR DEPLOYED GOOGLE APPS SCRIPT WEB APP URL
const GOOGLE_SCRIPT_URL = 'INSERT_YOUR_GOOGLE_APPS_SCRIPT_URL_HERE';

export const api = {
  /**
   * Fetches all site content (Config, Services, Events) from Google Sheets
   */
  fetchSiteData: async (): Promise<SiteData | null> => {
    if (GOOGLE_SCRIPT_URL === 'INSERT_YOUR_GOOGLE_APPS_SCRIPT_URL_HERE') {
      console.warn("Google Sheet URL not configured. Using fallback data.");
      return null;
    }

    try {
      const response = await fetch(GOOGLE_SCRIPT_URL);
      if (!response.ok) throw new Error('Network response was not ok');
      const data = await response.json();
      return data as SiteData;
    } catch (error) {
      console.error("Failed to fetch site data:", error);
      return null;
    }
  },

  /**
   * Submits the contact/lead form to Google Sheets
   */
  submitLead: async (formData: any): Promise<boolean> => {
    if (GOOGLE_SCRIPT_URL === 'INSERT_YOUR_GOOGLE_APPS_SCRIPT_URL_HERE') {
      console.warn("Google Sheet URL not configured. Form data logged to console.", formData);
      return true; // Simulate success
    }

    try {
      // We use no-cors mode to send data to Google Scripts without CORS errors
      // Note: We won't get a readable JSON response in no-cors mode, but the data will save.
      await fetch(GOOGLE_SCRIPT_URL, {
        method: 'POST',
        mode: 'no-cors', 
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(formData),
      });
      return true;
    } catch (error) {
      console.error("Failed to submit lead:", error);
      return false;
    }
  }
};

