### **Step 2: Google Sheets & Script Setup (REQUIRED)**

For the website to become "editable" and actually submit data, you **MUST** do the following:

1.  **Create a New Google Sheet** named "Analytics Spire DB".
2.  **Create 4 Tabs** at the bottom with these exact names:
    *   `SiteConfig` (Columns: `Key`, `Value`)
    *   `Services` (Columns: `title`, `description`, `category`, `iconName`, `details`)
    *   `Events` (Columns: `title`, `date`, `location`, `description`, `image`)
    *   `Leads` (Columns: `Timestamp`, `Name`, `Email`, `Phone`, `Category`, `Message`)
3.  **Fill in `SiteConfig`** with these rows (Key in col A, Value in col B):
    *   `heroTitle` -> Identify. Innovate. Impact.
    *   `heroSubtitle` -> We help MSMEs and enterprises clarify their vision.
    *   (You can edit these later to change the site text instantly).
4.  **Open Extensions > Apps Script** in the Google Sheet.
5.  **Paste this code** into the script editor:

```javascript
function doGet() {
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  const config = getSheetData(ss.getSheetByName("SiteConfig"));
  const services = getSheetDataList(ss.getSheetByName("Services"));
  const events = getSheetDataList(ss.getSheetByName("Events"));

  // Convert config array to object
  const configObj = {};
  config.forEach(row => configObj[row.Key] = row.Value);

  const result = { config: configObj, services: services, events: events };

  return ContentService.createTextOutput(JSON.stringify(result))
    .setMimeType(ContentService.MimeType.JSON);
}

function doPost(e) {
  try {
    const ss = SpreadsheetApp.getActiveSpreadsheet();
    const sheet = ss.getSheetByName("Leads");
    const data = JSON.parse(e.postData.contents);

    sheet.appendRow([
      new Date(),
      data.name,
      data.email,
      data.phone,
      data.businessCategory,
      data.businessDetails
    ]);

    return ContentService.createTextOutput("Success").setMimeType(ContentService.MimeType.TEXT);
  } catch(err) {
    return ContentService.createTextOutput("Error").setMimeType(ContentService.MimeType.TEXT);
  }
}

// Helpers
function getSheetData(sheet) {
  const data = sheet.getDataRange().getValues();
  const headers = data.shift();
  return data.map(row => {
    let obj = {};
    headers.forEach((h, i) => obj[h] = row[i]);
    return obj;
  });
}
function getSheetDataList(sheet) {
  const data = sheet.getDataRange().getValues();
  const headers = data.shift();
  return data.map(row => {
    let obj = {};
    headers.forEach((h, i) => {
      if(h === 'details') obj[h] = row[i].toString().split(',');
      else obj[h] = row[i];
    });
    return obj;
  });
}
```

6.  **Deploy**: Click **Deploy > New Deployment**.
    *   Select type: **Web app**.
    *   Execute as: **Me**.
    *   Who has access: **Anyone** (Important!).
7.  **Copy the Web App URL** and paste it into `services/api.ts` where it says `INSERT_YOUR_GOOGLE_APPS_SCRIPT_URL_HERE`.

